var (
	// landCommitGitRunner runs the trailing evidence commit's git subprocess. It
	// is a package var so tests can simulate a slow / cap-violating commit that
	// leaves a stale .git/index.lock behind (ddx-9b012b6c).
	landCommitGitRunner = func(ctx context.Context, dir string, args ...string) ([]byte, error) {
		return internalgit.Command(ctx, dir, args...).CombinedOutput()
	}

	// indexLockOwnerLookup resolves the live owner of an index.lock path. It is
	// a package var so the verified-stale vs live-owner distinction in
	// recoverStaleIndexLockAfterCommitCancel can be tested without depending on
	// lsof availability in CI.
	indexLockOwnerLookup = gitlock.IndexLockOwner
)

// landIndexCommitTimeout bounds a single evidence-commit git subprocess. It is
// the index.lock cap when cap enforcement is active so a slow commit cannot hold
// .git/index.lock past the cap watchdog: the subprocess is cancelled at the cap
// and the stale lock it leaves is recovered, rather than the watchdog
// force-releasing the lock out from under a still-running git process
// (ddx-9b012b6c). Zero (no cap) leaves the commit unbounded.
func landIndexCommitTimeout() time.Duration {
	if cfg := lockmetrics.CapConfigFor("index.lock"); cfg.Cap > 0 {
		return cfg.Cap
	}
	return 0
}

// commitStagedWithIndexLockRecovery runs the staged-commit git command under the
// index.lock metric+cap wrapper with stale-lock recovery, mirroring the
// durable-audit commit path (cli/internal/agent/durable_audit.go). The cap
// watchdog records the over-long hold as a durable violation; the cap-bounded
// timeout cancels the subprocess; and on cancellation the worktree's stale
// index.lock is recovered so the next tracker-only or evidence commit proceeds
// without manual lsof+rm cleanup. Only a verified-stale lock is removed — a lock
// held by a live process is left in place (AC3).
func commitStagedWithIndexLockRecovery(dir string, args ...string) ([]byte, error) {
	timeout := landIndexCommitTimeout()
	var out []byte
	err := lockmetrics.Instrument("index.lock", "index.commit", func() error {
		var lastErr error
		var lastDiag string
		for attempt := 0; attempt < gitlock.RecoveryAttempts; attempt++ {
			out, lastErr = runLandCommitWithTimeout(dir, timeout, args...)
			if lastErr == nil {
				return nil
			}
			if errors.Is(lastErr, context.DeadlineExceeded) || errors.Is(lastErr, context.Canceled) {
				return lastErr
			}
			if !gitlock.IsTransientGitContention(string(out), lastErr) {
				return lastErr
			}
			result, recErr := gitlock.RecoverGitIndexLock(dir)
			if recErr != nil {
				return fmt.Errorf("%s; index-lock recovery failed: %w", strings.TrimSpace(string(out)), recErr)
			}
			lastDiag = result.Reason
			if !result.Removed {
				time.Sleep(gitlock.LiveOwnerWait)
			}
		}
		return fmt.Errorf("%s; index-lock recovery exhausted after %d attempts: %s",
			strings.TrimSpace(string(out)), gitlock.RecoveryAttempts, lastDiag)
	})
	if errors.Is(err, context.DeadlineExceeded) || errors.Is(err, context.Canceled) {
		recoverStaleIndexLockAfterCommitCancel(dir)

// Package lockmetrics emits structured acquire/release events for the
// process-shared locks DDx workers hold around git index and tracker
// mutations (.git/index.lock and .ddx/.git-tracker.lock). Each held critical
// section produces two JSON-line events — one "acquire" and one "release" —
// so operators can see how long a worker held a lock and which operation held
// it, instead of inferring from filesystem mtimes and ps output.
//
// Events are routed through a process-wide sink. The default sink is nil
// (a no-op): instrumentation at the lock seams is therefore zero-cost unless
// an entrypoint enables a sink. The `ddx work` and `ddx run` commands enable
// the file sink so lock activity for a run is captured at
// .ddx/metrics/locks.jsonl, where it can be read back via Load.
package lockmetrics

import (
	"bufio"
	"encoding/json"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

const (
	// MaxActiveSizeBytes is the maximum size of the active locks.jsonl before
	// it is rotated to a timestamped archive. Set to 4 MiB so the file stays
	// safely below the 5 MiB pre-commit large-file guard (lefthook.yml).
	MaxActiveSizeBytes = 4 * 1024 * 1024

	// MaxRotatedArchives is the number of timestamped archives retained
	// alongside the active file. Archives beyond this count are pruned oldest-first.
	MaxRotatedArchives = 3
)

// Event is one lock lifecycle event. An acquire event carries the
// acquisition-time fields; the matching release event additionally carries
// ReleasedAt and DurationMS so the held window is fully described. A
// "violation" event is emitted when a hold exceeds its configured cap (see
// InstrumentCapped) and carries Severity "error" and CapMS.
type Event struct {
	// Event is "acquire", "release", or "violation".
	Event string `json:"event"`
	// LockName identifies the lock, e.g. "index.lock" or "tracker.lock".
	LockName string `json:"lock_name"`
	// Operation labels the work that held the lock, e.g. "tracker.commit"
	// or "index.commit".
	Operation string `json:"operation"`
	// HolderPID is the pid of the process that held the lock.
	HolderPID int `json:"holder_pid"`
	// AcquiredAt is the RFC3339Nano timestamp the lock was acquired.
	AcquiredAt string `json:"acquired_at"`
	// ReleasedAt is the RFC3339Nano timestamp the lock was released.
	// Empty on the acquire event.
	ReleasedAt string `json:"released_at,omitempty"`
	// DurationMS is the held duration in milliseconds. On a release event it
	// is ReleasedAt minus AcquiredAt; on a violation event it is the hold so
	// far at the moment the cap tripped. Zero on the acquire event.
	DurationMS int64 `json:"duration_ms,omitempty"`
	// Severity is "error" on a "violation" event; empty otherwise.
	Severity string `json:"severity,omitempty"`
	// CapMS is the configured hold-time cap in milliseconds. Set only on a
	// "violation" event.
	CapMS int64 `json:"cap_ms,omitempty"`
}

var (
	sinkMu sync.RWMutex
	sink   func(Event)
)

// SetSink installs the process-wide event sink. Passing nil disables event
// emission (the default). Safe for concurrent use.
func SetSink(fn func(Event)) {
	sinkMu.Lock()
	sink = fn
	sinkMu.Unlock()
}

// Emit routes ev to the current sink if one is installed; otherwise it is a
// no-op. Safe for concurrent use.
func Emit(ev Event) {
	sinkMu.RLock()
	fn := sink
	sinkMu.RUnlock()
	if fn != nil {
		fn(ev)
	}
}

// Instrument records the held window of an already-acquired lock: it emits an
// "acquire" event, runs critical, then emits a matching "release" event with
// the measured hold duration. The holder pid is the current process. The
// release event is emitted even if critical panics. critical's error is
// returned unchanged.
//
// When process-wide cap enforcement is enabled (see SetCapEnforcement),
// Instrument additionally arms a hold-time cap for the lock; otherwise it is a
// pure metric wrapper.
func Instrument(lockName, operation string, critical func() error) error {
	return InstrumentCapped(lockName, operation, resolveCapConfig(lockName), critical)
}

// Path returns the absolute path to the lock-events stream under the project's
// DDx state root: .ddx/metrics/locks.jsonl.
func Path(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, "metrics", "locks.jsonl")
}

// FileSink returns a sink that appends each event as one JSON line to
// Path(projectRoot). Appends are serialized with O_APPEND and an internal
// mutex so concurrent workers in one process do not interleave partial lines.
// Write errors are best-effort and discarded — observability must never break
// the operation being observed.
func FileSink(projectRoot string) func(Event) {
	path := Path(projectRoot)
	var mu sync.Mutex
	return func(ev Event) {
		mu.Lock()
		defer mu.Unlock()
		_ = appendEvent(path, ev)
	}
}

func appendEvent(path string, ev Event) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	if fi, err := os.Stat(path); err == nil && fi.Size() >= MaxActiveSizeBytes {
		_ = rotateLockMetrics(path)
	}
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
	if err != nil {
		return err
	}
	defer f.Close() //nolint:errcheck
	data, err := json.Marshal(ev)
	if err != nil {
		return err
	}
	data = append(data, '\n')
	_, err = f.Write(data)
	return err
}

// RotateIfNeeded renames path to a timestamped archive when its size is at or
// above MaxActiveSizeBytes, then prunes archives beyond MaxRotatedArchives.
// It is a no-op when the file does not exist or is within the size limit.
func RotateIfNeeded(path string) error {
	fi, err := os.Stat(path)
	if os.IsNotExist(err) || (err == nil && fi.Size() < MaxActiveSizeBytes) {
		return nil
	}
	if err != nil {
		return err
	}
	return rotateLockMetrics(path)
}

func rotateLockMetrics(path string) error {
	archive := path + "." + time.Now().UTC().Format("20060102T150405")
	if err := os.Rename(path, archive); err != nil {
		return err
	}
	return pruneOldArchives(path)
}

func pruneOldArchives(activePath string) error {
	dir := filepath.Dir(activePath)
	prefix := filepath.Base(activePath) + "."
	entries, err := os.ReadDir(dir)
	if err != nil {
		return err
	}
	var archives []string
	for _, e := range entries {
		if strings.HasPrefix(e.Name(), prefix) && !e.IsDir() {
			archives = append(archives, filepath.Join(dir, e.Name()))
		}
	}
	sort.Strings(archives)
	for len(archives) > MaxRotatedArchives {
		_ = os.Remove(archives[0])
		archives = archives[1:]
	}
	return nil
}

// Load reads all events from Path(projectRoot). Malformed lines are skipped.
// A missing file is not an error; it returns an empty slice.
func Load(projectRoot string) ([]Event, error) {
	f, err := os.Open(Path(projectRoot))
	if err != nil {
		if os.IsNotExist(err) {
			return []Event{}, nil
		}
		return nil, err
	}
	defer f.Close() //nolint:errcheck

	var events []Event
	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 64*1024), 1024*1024)
	for sc.Scan() {
		var ev Event
		if err := json.Unmarshal(sc.Bytes(), &ev); err != nil {
			continue
		}
		events = append(events, ev)
	}
	return events, sc.Err()
}

package lockmetrics

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"runtime/debug"
	"strconv"
	"sync"
	"sync/atomic"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Default hold-time caps. A worker that holds one of the named locks past its
// cap is treated as hung: the lock is force-released and the violation is
// surfaced, rather than letting the indefinite hold cascade into tracker-lock
// timeouts (the failure mode observed 2026-05-17).
const (
	DefaultIndexLockCap   = 10 * time.Second
	DefaultTrackerLockCap = 30 * time.Second
)

// CapFor returns the configured hold-time cap for lockName. The defaults are
// DefaultIndexLockCap for "index.lock" and DefaultTrackerLockCap for
// "tracker.lock", each overridable via the DDX_LOCK_CAP_INDEX_MS /
// DDX_LOCK_CAP_TRACKER_MS environment variables (milliseconds). Any other lock
// name has no cap and returns 0.
func CapFor(lockName string) time.Duration {
	switch lockName {
	case "index.lock":
		return capFromEnv("DDX_LOCK_CAP_INDEX_MS", DefaultIndexLockCap)
	case "tracker.lock":
		return capFromEnv("DDX_LOCK_CAP_TRACKER_MS", DefaultTrackerLockCap)
	default:
		return 0
	}
}

// capFromEnv reads a millisecond cap from the named environment variable,
// falling back to def when the variable is unset, empty, or not a positive
// integer.
func capFromEnv(name string, def time.Duration) time.Duration {
	v := os.Getenv(name)
	if v == "" {
		return def
	}
	ms, err := strconv.Atoi(v)
	if err != nil || ms <= 0 {
		return def
	}
	return time.Duration(ms) * time.Millisecond
}

// CapConfig parameterises hold-time cap enforcement for a single instrumented
// lock window. The zero value disables enforcement, so InstrumentCapped then
// behaves exactly like a pure metric wrapper.
type CapConfig struct {
	// Cap is the maximum hold time. Zero or negative disables enforcement.
	Cap time.Duration
	// LockPath is the filesystem path force-released (os.RemoveAll) when the
	// cap is exceeded. Empty skips force-release.
	LockPath string
	// EvidenceDir receives lock-violation.json when the cap is exceeded.
	// Empty skips the evidence record.
	EvidenceDir string
}

// Violation records a lock held past its configured cap. It is written to
// <EvidenceDir>/lock-violation.json so the post-execution reviewer sees the
// over-long hold even though the worker continues.
type Violation struct {
	LockName     string `json:"lock_name"`
	CapMS        int64  `json:"cap_ms"`
	ActualHoldMS int64  `json:"actual_hold_ms"`
	HolderPID    int    `json:"holder_pid"`
	Stack        string `json:"stack"`
}

// InstrumentCapped behaves like Instrument but additionally enforces a
// hold-time cap. It emits an "acquire" event, runs critical, and emits a
// matching "release" event. If cfg.Cap > 0 and the hold exceeds the cap, a
// watchdog fires once: it captures a stack trace, force-releases the lock by
// removing cfg.LockPath, writes <cfg.EvidenceDir>/lock-violation.json, and
// emits an error-severity "violation" event via the metric helper.
//
// The critical section is NOT interrupted — it runs to completion
// (release-only behaviour); the forced release and violation record are the
// loud signal that a hold ran too long. critical's error is returned
// unchanged.
func InstrumentCapped(lockName, operation string, cfg CapConfig, critical func() error) (err error) {
	pid := os.Getpid()
	acquiredAt := time.Now()
	Emit(Event{
		Event:      "acquire",
		LockName:   lockName,
		Operation:  operation,
		HolderPID:  pid,
		AcquiredAt: acquiredAt.UTC().Format(time.RFC3339Nano),
	})

	var timer *time.Timer
	var capViolated atomic.Bool
	if cfg.Cap > 0 {
		timer = time.AfterFunc(cfg.Cap, func() {
			capViolated.Store(true)
			enforceCapViolation(lockName, operation, pid, acquiredAt, cfg)
		})
	}

	defer func() {
		if timer != nil {
			timer.Stop()
		}
		if capViolated.Load() && cfg.LockPath != "" {
			_ = os.RemoveAll(cfg.LockPath)
		}
		releasedAt := time.Now()
		Emit(Event{
			Event:      "release",
			LockName:   lockName,
			Operation:  operation,
			HolderPID:  pid,
			AcquiredAt: acquiredAt.UTC().Format(time.RFC3339Nano),
			ReleasedAt: releasedAt.UTC().Format(time.RFC3339Nano),
			DurationMS: releasedAt.Sub(acquiredAt).Milliseconds(),
		})
	}()
	return critical()
}

// enforceCapViolation is the watchdog action run when a hold exceeds its cap:
// force-release the lock, write the evidence record, and emit the error event.
func enforceCapViolation(lockName, operation string, pid int, acquiredAt time.Time, cfg CapConfig) {
	held := time.Since(acquiredAt)
	stack := string(debug.Stack())

	if cfg.LockPath != "" {
		_ = os.RemoveAll(cfg.LockPath)
	}

	if cfg.EvidenceDir != "" {
		_ = writeViolation(cfg.EvidenceDir, Violation{
			LockName:     lockName,
			CapMS:        cfg.Cap.Milliseconds(),
			ActualHoldMS: held.Milliseconds(),
			HolderPID:    pid,
			Stack:        stack,
		})
	}

	Emit(Event{
		Event:      "violation",
		LockName:   lockName,
		Operation:  operation,
		HolderPID:  pid,
		AcquiredAt: acquiredAt.UTC().Format(time.RFC3339Nano),
		Severity:   "error",
		CapMS:      cfg.Cap.Milliseconds(),
		DurationMS: held.Milliseconds(),
	})
}

// writeViolation writes v as lock-violation.json under evidenceDir.
func writeViolation(evidenceDir string, v Violation) error {
	if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
		return err
	}
	data, err := json.MarshalIndent(v, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(filepath.Join(evidenceDir, "lock-violation.json"), data, 0o644)
}

var (
	capEnfMu       sync.RWMutex
	capEnabled     bool
	capProjectRoot string
	capEvidenceDir string
)

// SetCapEnforcement enables hold-time cap enforcement process-wide for the two
// named locks. projectRoot locates the lock files to force-release;
// evidenceDir (may be "") receives lock-violation.json on a violation. Passing
// an empty projectRoot disables enforcement (the default), leaving Instrument
// a pure metric wrapper. Safe for concurrent use.
func SetCapEnforcement(projectRoot, evidenceDir string) {
	capEnfMu.Lock()
	defer capEnfMu.Unlock()
	capProjectRoot = projectRoot
	capEvidenceDir = evidenceDir
	capEnabled = projectRoot != ""
}

// resolveCapConfig builds the CapConfig that Instrument applies to lockName
// from the process-wide enforcement state. It returns the zero CapConfig
// (no enforcement) when enforcement is disabled or lockName has no cap.
func resolveCapConfig(lockName string) CapConfig {
	capEnfMu.RLock()
	enabled := capEnabled
	root := capProjectRoot
	evidence := capEvidenceDir
	capEnfMu.RUnlock()

	if !enabled {
		return CapConfig{}
	}
	capDur := CapFor(lockName)
	if capDur <= 0 {
		return CapConfig{}
	}
	return CapConfig{
		Cap:         capDur,
		LockPath:    lockPathFor(root, lockName),
		EvidenceDir: evidence,
	}
}

// CapConfigFor returns the process-wide CapConfig for lockName. Callers that
// need to route through InstrumentCapped explicitly can use this instead of
// Instrument's internal helper.
func CapConfigFor(lockName string) CapConfig {
	return resolveCapConfig(lockName)
}

// SharedMainGitLockRoot resolves the DDx state root that should own the
// process-shared main-git lock. Linked worktrees converge on the primary
// workspace when one is available; otherwise the caller falls back to the
// standard project-scoped DDx path.
func SharedMainGitLockRoot(projectRoot string) string {
	if workspace := gitpkg.FindNearestDDxWorkspace(projectRoot); workspace != "" {
		if info, err := os.Stat(filepath.Join(workspace, ddxroot.DirName)); err == nil && info.IsDir() {
			return workspace
		}
	}
	return ddxroot.Path(context.Background(), projectRoot)

package lockmetrics

import (
	"encoding/json"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func scrubbedGitEnv() []string {
	env := os.Environ()
	out := make([]string, 0, len(env)+1)
	for _, kv := range env {
		if strings.HasPrefix(kv, "GIT_") {
			continue
		}
		out = append(out, kv)
	}
	return append(out, "GIT_CONFIG_NOSYSTEM=1")
}

func initTrackerLockRepo(t *testing.T) string {
	t.Helper()

	root := t.TempDir()
	run := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnv()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	run("init", "-b", "main")
	run("config", "user.email", "test@ddx.test")
	run("config", "user.name", "DDx Test")

	require.NoError(t, os.WriteFile(filepath.Join(root, "seed.txt"), []byte("seed\n"), 0o644))
	run("add", "seed.txt")
	run("commit", "-m", "chore: initial seed")

	require.NoError(t, os.MkdirAll(filepath.Join(root, ddxroot.DirName), 0o755))
	return root
}

// TestLockCap_DefaultIndexLockCap10s asserts the default cap for
// .git/index.lock is 10s and is overridable via DDX_LOCK_CAP_INDEX_MS.
func TestLockCap_DefaultIndexLockCap10s(t *testing.T) {
	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "")
	assert.Equal(t, 10*time.Second, CapFor("index.lock"),
		"default index.lock cap must be 10s")

	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "2500")
	assert.Equal(t, 2500*time.Millisecond, CapFor("index.lock"),
		"index.lock cap must be configurable via DDX_LOCK_CAP_INDEX_MS")
}

// TestLockCap_ExceedingCapForceReleases asserts that holding past the cap
// triggers a forced release and the underlying lock file is removed.
func TestLockCap_ExceedingCapForceReleases(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	err := InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	})
	require.NoError(t, err)

	_, statErr := os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr),
		"lock file must be force-released after exceeding the cap")
}

// TestLockCap_ExceedingCapRemovesLockRecreatedAfterWatchdog asserts the
// release path cleans up a lock file recreated by a slow git subprocess after
// the watchdog's first forced removal.
func TestLockCap_ExceedingCapRemovesLockRecreatedAfterWatchdog(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	err := InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(100 * time.Millisecond)
		require.NoError(t, os.WriteFile(lockPath, []byte("recreated"), 0o644))
		return nil
	})
	require.NoError(t, err)

	_, statErr := os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr),
		"release path must remove lock files recreated after the cap watchdog fires")
}

// TestLockCap_ViolationWrittenToEvidence asserts a lock-violation.json appears
// under the worker's evidence directory carrying the required fields.
func TestLockCap_ViolationWrittenToEvidence(t *testing.T) {
	SetSink(nil)
	dir := t.TempDir()
	evidence := filepath.Join(dir, "20260527T021507-08bcbb0f")
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: evidence}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	}))

	data, err := os.ReadFile(filepath.Join(evidence, "lock-violation.json"))
	require.NoError(t, err, "lock-violation.json must exist under the evidence dir")

	var v Violation
	require.NoError(t, json.Unmarshal(data, &v))
	assert.Equal(t, "index.lock", v.LockName)
	assert.Equal(t, int64(30), v.CapMS)
	assert.GreaterOrEqual(t, v.ActualHoldMS, int64(30),
		"actual_hold_ms must be at least the cap")
	assert.Equal(t, os.Getpid(), v.HolderPID)
	assert.NotEmpty(t, v.Stack, "violation record must include a stack trace")
}

// TestLockCap_ViolationLoggedAsError asserts an error-severity event is
// emitted via the metric helper when the cap is exceeded.
func TestLockCap_ViolationLoggedAsError(t *testing.T) {
	snapshot := capture(t)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 30 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		time.Sleep(200 * time.Millisecond)
		return nil
	}))

	var violation *Event
	for _, ev := range snapshot() {
		if ev.Event == "violation" {
			ev := ev
			violation = &ev
		}
	}
	require.NotNil(t, violation, "expected a violation event")
	assert.Equal(t, "error", violation.Severity)
	assert.Equal(t, "index.lock", violation.LockName)
	assert.Equal(t, int64(30), violation.CapMS)
}

// TestLockCap_WithinCapDoesNotForceRelease asserts that a hold under the cap
// neither removes the lock nor records a violation.
func TestLockCap_WithinCapDoesNotForceRelease(t *testing.T) {
	snapshot := capture(t)
	dir := t.TempDir()
	lockPath := filepath.Join(dir, "index.lock")
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))

	cfg := CapConfig{Cap: 200 * time.Millisecond, LockPath: lockPath, EvidenceDir: dir}
	require.NoError(t, InstrumentCapped("index.lock", "index.commit", cfg, func() error {
		return nil
	}))

	_, statErr := os.Stat(lockPath)
	assert.NoError(t, statErr, "lock file must survive a within-cap hold")
	_, vErr := os.Stat(filepath.Join(dir, "lock-violation.json"))
	assert.True(t, os.IsNotExist(vErr), "no violation record for a within-cap hold")
	for _, ev := range snapshot() {
		assert.NotEqual(t, "violation", ev.Event, "no violation event for a within-cap hold")
	}
}

// TestLockCap_DefaultTrackerLockCap30s asserts the default cap for
// .ddx/.git-tracker.lock is 30s and is overridable via DDX_LOCK_CAP_TRACKER_MS.
func TestLockCap_DefaultTrackerLockCap30s(t *testing.T) {
	t.Setenv("DDX_LOCK_CAP_TRACKER_MS", "")
	assert.Equal(t, 30*time.Second, CapFor("tracker.lock"))

	t.Setenv("DDX_LOCK_CAP_TRACKER_MS", "5000")
	assert.Equal(t, 5*time.Second, CapFor("tracker.lock"))
}

// TestLockCap_NoEnforcementWhenDisabled asserts that with cap enforcement off
// (the default), Instrument resolves no cap for the named locks.
func TestLockCap_NoEnforcementWhenDisabled(t *testing.T) {
	SetCapEnforcement("", "")
	t.Cleanup(func() { SetCapEnforcement("", "") })
	assert.Equal(t, CapConfig{}, resolveCapConfig("index.lock"))
	assert.Equal(t, CapConfig{}, resolveCapConfig("tracker.lock"))
}

// TestLockCap_EnforcementResolvesLockPaths asserts that enabling enforcement
// resolves the on-disk lock paths for the two named locks under projectRoot.
func TestLockCap_EnforcementResolvesLockPaths(t *testing.T) {
	root := t.TempDir()
	SetCapEnforcement(root, filepath.Join(root, "evidence"))
	t.Cleanup(func() { SetCapEnforcement("", "") })

	idx := resolveCapConfig("index.lock")
	assert.Equal(t, filepath.Join(root, ".git", "index.lock"), idx.LockPath)
	assert.Greater(t, idx.Cap, time.Duration(0))

	trk := resolveCapConfig("tracker.lock")
	assert.Contains(t, trk.LockPath, ".git-tracker.lock")
	assert.Greater(t, trk.Cap, time.Duration(0))
}

// TestLockCap_TrackerLockPathUsesSharedMainGitRoot asserts that tracker.lock
// cap enforcement resolves through the shared main-worktree DDx root when the
// request originates from a linked worktree.
func TestLockCap_TrackerLockPathUsesSharedMainGitRoot(t *testing.T) {
	root := initTrackerLockRepo(t)
	linked := filepath.Join(t.TempDir(), "linked")
	runGit := func(args ...string) {
		cmd := exec.Command("git", args...)
		cmd.Dir = root
		cmd.Env = scrubbedGitEnv()
		out, err := cmd.CombinedOutput()
		if err != nil {
			t.Fatalf("git %v: %v\n%s", args, err, out)
		}
	}

	runGit("worktree", "add", "--detach", linked)
	t.Cleanup(func() { runGit("worktree", "remove", "--force", linked) })
	t.Cleanup(func() { SetCapEnforcement("", "") })

	SetCapEnforcement(linked, filepath.Join(linked, "evidence"))

	trk := resolveCapConfig("tracker.lock")
	wantRoot := SharedMainGitLockRoot(linked)
	assert.Equal(t, root, wantRoot, "linked worktrees must resolve tracker caps through the primary workspace")
	assert.Equal(t, filepath.Join(root, ddxroot.DirName, ".git-tracker.lock"), trk.LockPath)
	assert.Equal(t, filepath.Join(wantRoot, ddxroot.DirName, ".git-tracker.lock"), trk.LockPath)
	assert.Greater(t, trk.Cap, time.Duration(0))
}

package agent

// execute_bead_land_index_lock_test.go — recovery of stale .git/index.lock left
// behind when the trailing evidence commit is capped/cancelled mid-flight
// (ddx-9b012b6c). The land evidence commit runs under the index.lock cap; a
// hold past the cap force-releases the lock and can leave an interrupted
// commit's stale lock behind, which used to block the next tracker-only commit
// until an operator removed it manually.

import (
	"context"
	"errors"
	"os"
	"path/filepath"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestLandEvidenceCommit_IndexLockCapDoesNotLeaveStaleLock proves that when the
// evidence commit subprocess stalls past the index.lock cap and is cancelled,
// the worktree's stale .git/index.lock is recovered so nothing is left behind.
func TestLandEvidenceCommit_IndexLockCapDoesNotLeaveStaleLock(t *testing.T) {
	r := newLandTestRepo(t)
	lockPath := worktreeIndexLockPath(r.dir)

	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "25")
	lockmetrics.SetCapEnforcement(r.dir, t.TempDir())
	t.Cleanup(func() { lockmetrics.SetCapEnforcement("", "") })
	lockmetrics.SetSink(nil)
	t.Cleanup(func() { lockmetrics.SetSink(nil) })

	origRunner := landCommitGitRunner
	t.Cleanup(func() { landCommitGitRunner = origRunner })

	var sawDeadline bool
	landCommitGitRunner = func(ctx context.Context, dir string, args ...string) ([]byte, error) {
		// Simulate git taking the index lock then stalling past the cap.
		require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))
		<-ctx.Done()
		if errors.Is(ctx.Err(), context.DeadlineExceeded) {
			sawDeadline = true
		}
		return nil, ctx.Err()
	}

	start := time.Now()
	_, err := commitStagedWithIndexLockRecovery(r.dir, "commit", "-m", "evidence")
	require.Error(t, err)
	assert.True(t, sawDeadline, "evidence commit must receive the cap-bounded deadline")
	assert.Less(t, time.Since(start), 500*time.Millisecond,
		"capped commit must not outlive the index lock cap budget")

	_, statErr := os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr),
		"capped/cancelled evidence commit must not leave a stale .git/index.lock")
}

// TestExecuteBeadLoop_IndexCommitLockViolationReleasesAndContinues proves the
// worker records the index.lock cap violation, recovers the stale lock, and a
// subsequent tracker-only commit proceeds without manual lock removal.
func TestExecuteBeadLoop_IndexCommitLockViolationReleasesAndContinues(t *testing.T) {
	r := newLandTestRepo(t)
	lockPath := worktreeIndexLockPath(r.dir)

	t.Setenv("DDX_LOCK_CAP_INDEX_MS", "25")
	lockmetrics.SetCapEnforcement(r.dir, t.TempDir())
	t.Cleanup(func() { lockmetrics.SetCapEnforcement("", "") })

	var eventsMu sync.Mutex
	var events []lockmetrics.Event
	lockmetrics.SetSink(func(ev lockmetrics.Event) {
		eventsMu.Lock()
		events = append(events, ev)
		eventsMu.Unlock()
	})
	t.Cleanup(func() { lockmetrics.SetSink(nil) })

	origRunner := landCommitGitRunner
	t.Cleanup(func() { landCommitGitRunner = origRunner })

	landCommitGitRunner = func(ctx context.Context, dir string, args ...string) ([]byte, error) {
		// Hold the index lock well past the cap so the watchdog records a
		// violation, then leave a stale lock behind as an interrupted commit
		// would after the watchdog's first force-release.
		require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))
		time.Sleep(120 * time.Millisecond)
		require.NoError(t, os.WriteFile(lockPath, []byte("recreated"), 0o644))
		return nil, ctx.Err()
	}

	_, err := commitStagedWithIndexLockRecovery(r.dir, "commit", "-m", "evidence")
	require.Error(t, err)

	// Restore the real runner so the follow-up commit reflects normal operation.
	landCommitGitRunner = origRunner

	eventsMu.Lock()
	var sawViolation bool
	for _, ev := range events {
		if ev.Event == "violation" && ev.LockName == "index.lock" {
			sawViolation = true
			assert.Equal(t, "error", ev.Severity, "index.lock violation must be error severity")
		}
	}
	eventsMu.Unlock()
	assert.True(t, sawViolation, "over-cap evidence commit must record an index.lock violation")

	_, statErr := os.Stat(lockPath)
	require.True(t, os.IsNotExist(statErr),
		"stale index.lock must be recovered after the capped commit")

	// A subsequent tracker-only commit must proceed without manual lock removal.
	r.writeFile("follow-up.txt", "after recovery\n")
	r.runGit("add", "-A")
	r.runGit("-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", "follow up")
}

// TestLandEvidenceCommit_StaleLockRecoveryLeavesLiveOwnerLock proves the cancel
// recovery distinguishes a verified-stale lock (no live owner → removed) from a
// lock held by a live process (left in place).
func TestLandEvidenceCommit_StaleLockRecoveryLeavesLiveOwnerLock(t *testing.T) {
	r := newLandTestRepo(t)
	lockPath := worktreeIndexLockPath(r.dir)
	require.NoError(t, os.MkdirAll(filepath.Dir(lockPath), 0o755))

	origLookup := indexLockOwnerLookup
	t.Cleanup(func() { indexLockOwnerLookup = origLookup })

	// Live owner: a running process holds the lock → it must NOT be removed.
	require.NoError(t, os.WriteFile(lockPath, []byte("held"), 0o644))
	indexLockOwnerLookup = func(string) (int, error) { return os.Getpid(), nil }
	recoverStaleIndexLockAfterCommitCancel(r.dir)
	_, statErr := os.Stat(lockPath)
	assert.NoError(t, statErr, "a lock held by a live owner must not be removed")

	// Verified-stale: no live owner → the lock is removed.
	indexLockOwnerLookup = func(string) (int, error) { return 0, nil }
	recoverStaleIndexLockAfterCommitCancel(r.dir)
	_, statErr = os.Stat(lockPath)
	assert.True(t, os.IsNotExist(statErr), "a lock with no live owner must be removed")
}

func TestCommitDurableAuditOutputs_ConcurrentLockHolderRetriesAndRecovers(t *testing.T) {
	t.Setenv("DDX_BIN", testutils.BuildDDxBinary(t))
	projectRoot := testutils.NewFixtureRepo(t, "standard")
	attemptID := "20260606T081500-audit-lock-recover"
	dirtyPath := filepath.Join(projectRoot, ddxroot.DirName, "metrics", "attempts.jsonl")
	require.NoError(t, os.MkdirAll(filepath.Dir(dirtyPath), 0o755))
	require.NoError(t, os.WriteFile(dirtyPath, []byte("dirty\n"), 0o644))
	headBefore := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	origTimeout := durableAuditGitTimeout
	origContextFactory := durableAuditCommandContext
	t.Cleanup(func() {
		durableAuditGitTimeout = origTimeout
		durableAuditCommandContext = origContextFactory
	})

	durableAuditGitTimeout = 100 * time.Millisecond
	var ctxMu sync.Mutex
	var firstContextAt time.Time
	durableAuditCommandContext = func() (context.Context, context.CancelFunc) {
		ctxMu.Lock()
		if firstContextAt.IsZero() {
			firstContextAt = time.Now()
		}
		ctxMu.Unlock()
		return context.WithTimeout(context.Background(), durableAuditGitTimeout)
	}

	locked := make(chan struct{})
	release := make(chan struct{})
	lockErrCh := make(chan error, 1)
	go func() {
		lockErrCh <- withTrackerLock(projectRoot, "durable_audit_test", func() error {
			close(locked)
			<-release
			return nil
		})
	}()

	<-locked
	time.Sleep(3 * durableAuditGitTimeout)

	commitErrCh := make(chan error, 1)
	go func() {
		commitErrCh <- CommitDurableAuditOutputs(projectRoot, attemptID)
	}()

	releaseAt := time.Now()
	close(release)
	require.NoError(t, <-lockErrCh)

	firstErr := <-commitErrCh
	if firstErr != nil {
		require.True(t, isTransientGitContention(firstErr), "expected transient contention error after lock contention, got %v", firstErr)
	}

	ctxMu.Lock()
	require.False(t, firstContextAt.IsZero(), "expected a git subprocess deadline context to be created")
	assert.False(t, firstContextAt.Before(releaseAt), "git subprocess deadline budget started before the tracker lock was released")
	ctxMu.Unlock()

	require.NoError(t, CommitDurableAuditOutputs(projectRoot, attemptID))

	statusArgs := append([]string{"status", "--short", "--"}, trackerpaths.ManagedPathspecs()...)
	assert.Empty(t, runGitInteg(t, projectRoot, statusArgs...))
	headAfter := runGitInteg(t, projectRoot, "rev-parse", "HEAD")
	assert.NotEqual(t, headBefore, headAfter)
}

func TestCommitDurableAuditOutputs_ResumesAfterPartialKill(t *testing.T) {
	t.Setenv("DDX_BIN", testutils.BuildDDxBinary(t))
	projectRoot := testutils.NewFixtureRepo(t, "standard")
	attemptID := "20260606T081600-audit-partial-kill"
	dirtyPath := filepath.Join(projectRoot, ddxroot.DirName, "metrics", "attempts.jsonl")
	require.NoError(t, os.MkdirAll(filepath.Dir(dirtyPath), 0o755))
	require.NoError(t, os.WriteFile(dirtyPath, []byte("dirty\n"), 0o644))
	headBefore := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	origRunner := durableAuditGitRunner
	t.Cleanup(func() {
		durableAuditGitRunner = origRunner
	})

	var commitAttempts int32
	durableAuditGitRunner = func(ctx context.Context, gitDir string, args ...string) ([]byte, error) {
		if len(args) > 0 && args[0] == "commit" && atomic.AddInt32(&commitAttempts, 1) == 1 {
			return []byte("signal: killed"), errors.New("signal: killed")
		}
		return origRunner(ctx, gitDir, args...)
	}

	require.NoError(t, CommitDurableAuditOutputs(projectRoot, attemptID))
	require.GreaterOrEqual(t, atomic.LoadInt32(&commitAttempts), int32(2), "the killed commit must be retried")
	headAfter := runGitInteg(t, projectRoot, "rev-parse", "HEAD")
	assert.NotEqual(t, headBefore, headAfter)
	statusArgs := append([]string{"status", "--short", "--"}, trackerpaths.ManagedPathspecs()...)
	assert.Empty(t, runGitInteg(t, projectRoot, statusArgs...))

	require.NoError(t, CommitDurableAuditOutputs(projectRoot, attemptID))
	headAfter = runGitInteg(t, projectRoot, "rev-parse", "HEAD")
	assert.NotEqual(t, headBefore, headAfter)
	assert.Empty(t, runGitInteg(t, projectRoot, statusArgs...))

	require.NoError(t, CommitDurableAuditOutputs(projectRoot, attemptID))
	assert.Equal(t, headAfter, runGitInteg(t, projectRoot, "rev-parse", "HEAD"))
	assert.Empty(t, runGitInteg(t, projectRoot, statusArgs...))
}

