func TestWork_TransientDurableAuditRetryBlocksNextClaim(t *testing.T) {
	projectRoot := newDurableAuditProject(t)
	inner := bead.NewStore(ddxroot.JoinProject(projectRoot))
	require.NoError(t, inner.Init(context.Background()))
	first := &bead.Bead{ID: "ddx-audit-retry-1", Title: "audit retry one", Priority: 0}
	second := &bead.Bead{ID: "ddx-audit-retry-2", Title: "audit retry two", Priority: 1}
	require.NoError(t, inner.Create(context.Background(), first))
	require.NoError(t, inner.Create(context.Background(), second))
	runGitInteg(t, projectRoot, "add", ".")
	runGitInteg(t, projectRoot, "commit", "-m", "chore: seed tracker")
	head := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	store := &claimCountingStore{Store: inner}
	var execCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCalls, 1)
			return ExecuteBeadReport{
				BeadID:      beadID,
				AttemptID:   "20260616T181500-audit-retry",
				Status:      ExecuteBeadStatusExecutionFailed,
				Detail:      "implementation failed",
				BaseRev:     head,
				ResultRev:   head,
				SessionID:   "sess-audit-retry",
				ProjectRoot: projectRoot,
			}, nil
		}),
	}

	oldRetry := retryPendingDurableAuditCommit
	var retryCalls int32
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	retryPendingDurableAuditCommit = func(projectRoot, attemptID string) error {
		atomic.AddInt32(&retryCalls, 1)
		cancel()
		return context.DeadlineExceeded
	}
	t.Cleanup(func() {
		retryPendingDurableAuditCommit = oldRetry
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		ProjectRoot: projectRoot,
		FinalizeDurableAudit: func(report ExecuteBeadReport) error {
			return fmt.Errorf("commit durable audit outputs: %w", context.DeadlineExceeded)
		},
	})

	require.ErrorIs(t, err, context.Canceled)
	require.NotNil(t, result)
	assert.Equal(t, int32(1), atomic.LoadInt32(&execCalls), "only the first bead may execute while its audit commit is pending")
	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "pending durable audit retry must block the next claim")
	assert.Equal(t, int32(1), atomic.LoadInt32(&retryCalls), "pending durable audit commit should be retried before candidate selection")
}

// TestIsTransientGitContention_SignalKilledAndDeadline asserts that the
// SIGKILL / context-deadline class and the tracker-lock-timeout string are
// each classified as transient (ddx-83361480).
func TestIsTransientGitContention_SignalKilledAndDeadline(t *testing.T) {
	trueFor := []struct {
		name string
		err  error
	}{
		{"unable_to_write_new_index_file", fmt.Errorf("committing tracker: fatal: unable to write new index file: exit status 128")},
		{"signal_killed_in_message", fmt.Errorf("commit durable audit outputs: committing durable audit outputs: : signal: killed")},
		{"context_deadline_exceeded_string", fmt.Errorf("context deadline exceeded")},
		{"tracker_lock_timeout_string", fmt.Errorf("tracker lock timeout (max elapsed, lock: .ddx/.git-tracker.lock, owner: 99)")},
		{"context_deadline_exceeded_sentinel", context.DeadlineExceeded},
		{"context_deadline_exceeded_wrapped", fmt.Errorf("commit durable audit: %w", context.DeadlineExceeded)},
	}
	for _, tc := range trueFor {
		t.Run(tc.name, func(t *testing.T) {
			require.True(t, isTransientGitContention(tc.err), "must be classified as transient")
		})
	}

	// Regression: genuine non-transient errors must not be misclassified.
	falseFor := []error{
		fmt.Errorf("committing tracker: fatal: insufficient permission for adding an object to repository database .git/objects: exit status 128"),
		fmt.Errorf("committing durable audit outputs: fatal: insufficient permission for adding an object to repository database .git/objects: exit status 128"),
		errors.New("disk full"),
		context.Canceled,
	}
	for _, err := range falseFor {
		require.False(t, isTransientGitContention(err), "must NOT be classified as transient: %v", err)
	}
}

package trackerpaths

import (
	"path/filepath"
	"strings"
)

var managedPathspecs = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
	".ddx/metrics/attempts.jsonl",
	".ddx/attachments",
}

var preClaimNonBlockingRoots = []string{
	".ddx/executions",
}

// ManagedPathspecs returns the DDx-managed tracker and durable-audit pathspecs.
// Callers must treat the returned slice as read-only.
func ManagedPathspecs() []string {
	return append([]string(nil), managedPathspecs...)
}

// IsManagedTrackerPath reports whether path is one of the DDx-managed tracker
// files or lives under the managed attachments directory.
func IsManagedTrackerPath(path string) bool {
	clean := cleanPath(path)
	if clean == "" {
		return false
	}
	for _, managed := range managedPathspecs {
		if pathInRoot(clean, managed) {
			return true
		}
	}
	return false
}

// IsNonBlockingPreClaimPath reports whether a staged path is DDx-owned
// metadata that must not block a worker's next claim. This intentionally
// includes ignored execution evidence, which is too broad for durable-audit
// force-staging but is still not operator code/doc/test work.
func IsNonBlockingPreClaimPath(path string) bool {
	clean := cleanPath(path)
	if clean == "" {
		return false
	}
	if IsManagedTrackerPath(clean) {
		return true
	}
	for _, root := range preClaimNonBlockingRoots {
		if pathInRoot(clean, root) {
			return true
		}
	}
	return false
}

func cleanPath(path string) string {
	return strings.TrimSpace(filepath.ToSlash(path))
}

func pathInRoot(clean, root string) bool {
	root = strings.TrimSuffix(filepath.ToSlash(root), "/")
	return clean == root || strings.HasPrefix(clean, root+"/")
}

